td {
  padding: 12px;
  border-bottom: 1px solid var(--border);
  font-size: 1.1rem;
}

/* Badges */
.badge {
  padding: 4px 8px;
  border-radius: 4px;
  font-weight: bold;
  font-size: 0.9rem;
}

.badge-critical {
  background: var(--danger);
  color: white;
}

.badge-high {
  background: var(--warning);
  color: #fff;
}

.badge-safe {
  background: var(--safe);
  color: white;
