appsmith.onReady(() => {
  const model = appsmith.model;
  renderGovernanceAudit(model);
});
appsmith.onModelChange(newModel => {
  renderGovernanceAudit(newModel);
});
function renderGovernanceAudit(model) {
  // Safety check: ensure networkData and the nested details array exist
  if (!model || !model.networkData || !model.networkData.details) return;
  const data = model.networkData.details || [];
  const policy = model.governance_policy || {};
  const tbody = document.getElementById('governance-body');
  if (!tbody) return;
  tbody.innerHTML = "";
  let violationCount = 0;
  let criticalRiskCount = 0;
  const entities = new Set();
  data.forEach(item => {
    entities.add(item.owner);

    // --- 1. Determine Synthesis Risk (Reality) ---
    // We split this into two parts to match the new "two squares" UI requirement
    let severity = "Low";
    let definition = "Limited Risk";
    let riskClass = "badge-safe";

    // Logic: 3+ fingerprinting points or specific ad-tracking domains trigger Critical
    if (item.domain.includes("googlesyndication") || item.fingerprinting >= 3) {
      severity = "CRITICAL";
      definition = "High Synthesis";
      riskClass = "badge-critical";
      criticalRiskCount++;
    } else if (item.fingerprinting >= 2) {
      severity = "HIGH";
      definition = "Re-identification";
      riskClass = "badge-high";
    }

    // --- 2. Compare against Governance Policy ---
    let status = "Compliant";
    let statusClass = "status-compliant";
    let detectedActivity = (item.categories || []).join(", ") || "General Connectivity";

    // Check for specific violations (Google LLC or AI Vendors)
    const isGoogleViolation = item.owner === "Google LLC" && item.domain.includes("googlesyndication");
    const isAIVendor = ["openai", "anthropic", "claude", "mistral"].some(ai => item.domain.includes(ai));
    if (isGoogleViolation || isAIVendor) {
      status = "VIOLATION";
      statusClass = "status-violation";
      violationCount++;
      detectedActivity = isAIVendor ? "Unsanctioned AI Model Ingestion" : "Prohibited Ad-Motivated Harvesting";
    }

    // --- 3. Render Row (Focus on Risks and Violations) ---
    // We only render items that are not "Low" risk OR are active violations
    if (severity !== "Low" || status === "VIOLATION") {
      const row = document.createElement('tr');
      row.innerHTML = `
                <td><code>${item.domain}</code></td>
                <td><strong>${item.owner || 'Unknown Entity'}</strong></td>
                <td>${detectedActivity}</td>
                <td>
                    <div class="risk-stack">
                        <span class="badge ${riskClass}">${severity}</span>
                        <span class="badge-sub">${definition}</span>
                    </div>
                </td>
                <td class="${statusClass}"><strong>${status}</strong></td>
            `;
      tbody.appendChild(row);
    }
  });

  // --- 4. Update Stats & Verdict Banner ---
  document.getElementById('entity-count').textContent = entities.size;
  document.getElementById('violation-count').textContent = violationCount;
  document.getElementById('critical-risk-count').textContent = criticalRiskCount;
  const banner = document.getElementById('verdict-banner');
  if (banner) {
    const bannerHeader = banner.querySelector('h2');
    if (violationCount > 0) {
      banner.className = "verdict-banner verdict-danger";
      bannerHeader.innerHTML = `
                ⚠️ GOVERNANCE FAILURE: ${violationCount} Active Violations
                <div style="font-size:0.9rem; font-weight:normal; margin-top:5px;">
                    Detected unauthorized data egress with high identity synthesis capabilities.
                </div>
            `;
    } else {
      banner.className = "verdict-banner verdict-safe";
      bannerHeader.textContent = "✅ Governance Protocols Active";
    }
  }
}

